    const nonce = crypto.randomBytes(16).toString('hex');
    const url = "https://depix.eulen.app/api/deposit";
    const headers = {
        "X-Nonce": nonce,
        "Authorization": "Bearer <token>", // Replace with your token
        "Content-Type": "application/json",
    };
    const body = {
        amountInCents: 100
    };

    const maxAttempts = 10;
    let attempts = 0;
    let asyncExpiration = null;

    while (true) {
        try {
            const response = await axios.post(url, body, { headers });
            const statusCode = response.status;

            if (![200, 201, 202].includes(statusCode)) {
                console.log(`Request failed with status code: ${statusCode}`);
                console.log(`Response: ${JSON.stringify(response.data)}`);
                break;
            }

            const data = response.data;

            if (data.async === false) {
                console.log(`Response received: ${JSON.stringify(data)}`);
                break;
            } else if (data.async === true) {
                if (!asyncExpiration) {
                    asyncExpiration = new Date(data.expiration);
                }

                if (new Date() >= asyncExpiration) {
                    console.log("Expiration reached. No response received in time.");
                    break;
                }

                console.log("Waiting for async response...");
                await new Promise(resolve => setTimeout(resolve, 1000));
            } else {
                console.log("Unexpected response format.");
                console.log(`Response: ${JSON.stringify(data)}`);
                break;
            }

        } catch (error) {
            attempts++;
            if (attempts >= maxAttempts) {
                console.log("Maximum number of attempts reached due to timeout.");
                break;
            }

            console.log("Request timed out. Retrying...");
            await new Promise(resolve => setTimeout(resolve, 1000));
        }
    }
}

