package main

import (
	"bytes"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"
	"time"
)

type Response struct {
	Async      bool   `json:"async"`
	Expiration string `json:"expiration,omitempty"`
	Response   struct {
		QrCopyPaste string `json:"qrCopyPaste,omitempty"`
		QrImageUrl  string `json:"qrImageUrl,omitempty"`
		ErrorMessage string `json:"errorMessage,omitempty"`
	} `json:"response,omitempty"`
}

func generateNonce() string {
	nonce := make([]byte, 16)
	_, err := rand.Read(nonce)
	if err != nil {
		panic("failed to generate nonce")
	}
	return hex.EncodeToString(nonce)
}

func main() {
	url := "https://depix.eulen.app/api/deposit"
	nonce := generateNonce()
	token := "<token>" // Replace with your token

	body := map[string]int{"amountInCents": 100}
	jsonBody, _ := json.Marshal(body)

	req, _ := http.NewRequest("POST", url, bytes.NewBuffer(jsonBody))
	req.Header.Set("X-Nonce", nonce)
	req.Header.Set("Authorization", "Bearer "+token)
	req.Header.Set("Content-Type", "application/json")

	client := &http.Client{Timeout: 10 * time.Second}
	maxAttempts := 10
	attempts := 0
	var asyncExpiration time.Time

	for {
		resp, err := client.Do(req)
		if err != nil {
			attempts++
			if attempts >= maxAttempts {
				fmt.Println("Maximum number of attempts reached due to timeout.")
				break
			}
			fmt.Println("Request timed out. Retrying...")
			time.Sleep(1 * time.Second)
			continue
		}

		defer resp.Body.Close()
		if resp.StatusCode != 200 && resp.StatusCode != 201 && resp.StatusCode != 202 {
			fmt.Printf("Request failed with status code: %d\n", resp.StatusCode)
			body, _ := ioutil.ReadAll(resp.Body)
			fmt.Printf("Response: %s\n", string(body))
			break
		}

		var response Response
		err = json.NewDecoder(resp.Body).Decode(&response)
		if err != nil {
			fmt.Println("Failed to parse response.")
			break
		}

		if !response.Async {
			fmt.Printf("Response received: %+v\n", response)
			break
		} else {
			if asyncExpiration.IsZero() {
				asyncExpiration, _ = time.Parse(time.RFC3339, response.Expiration)
			}
			if time.Now().After(asyncExpiration) {
				fmt.Println("Expiration reached. No response received in time.")
				break
			}
			fmt.Println("Waiting for async response...")
			time.Sleep(1 * time.Second)
		}
	}
}
