use reqwest::header::{HeaderMap, HeaderValue, AUTHORIZATION, CONTENT_TYPE};
use serde::{Deserialize, Serialize};
use std::time::{Duration, SystemTime};
use uuid::Uuid;
use tokio::time::sleep;

#[derive(Serialize)]
struct RequestBody {
    amount_in_cents: u64,
}

#[derive(Deserialize, Debug)]
struct ApiResponse {
    #[serde(default)]
    async_status: bool,
    #[serde(default)]
    expiration: Option<String>,
    #[serde(default)]
    response: Option<ResponseDetails>,
}

#[derive(Deserialize, Debug)]
struct ResponseDetails {
    #[serde(default)]
    qr_copy_paste: Option<String>,
    #[serde(default)]
    qr_image_url: Option<String>,
    #[serde(default)]
    error_message: Option<String>,
}

const MAX_ATTEMPTS: u8 = 10;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let token = "<token>"; // Replace with your token
    let url = "https://depix.eulen.app/api/deposit";
    let nonce = Uuid::new_v4().to_string();
    let client = reqwest::Client::new();

    let mut headers = HeaderMap::new();
    headers.insert("X-Nonce", HeaderValue::from_str(&nonce)?);
    headers.insert(AUTHORIZATION, HeaderValue::from_str(&format!("Bearer {}", token))?);
    headers.insert(CONTENT_TYPE, HeaderValue::from_static("application/json"));

    let body = RequestBody {
        amount_in_cents: 100,
    };

    let mut attempts = 0;
    let mut async_expiration: Option<SystemTime> = None;

    loop {
        let response = client
            .post(url)
            .headers(headers.clone())
            .json(&body)
            .send()
            .await;

        if let Err(err) = response {
            attempts += 1;
            if attempts >= MAX_ATTEMPTS {
                println!("Maximum number of attempts reached due to timeout.");
                break;
            }
            println!("Request failed: {}. Retrying...", err);
            sleep(Duration::from_secs(1)).await;
            continue;
        }

        let response = response.unwrap();
        let status = response.status().as_u16();

        if status != 200 && status != 201 && status != 202 {
            println!("Request failed with status code: {}", status);
            let text = response.text().await.unwrap_or_else(|_| "Unknown error".to_string());
            println!("Response: {}", text);
            break;
        }

        let data: ApiResponse = response.json().await.unwrap();

        if !data.async_status {
            println!("Response received: {:?}", data);
            break;
        } else {
            if async_expiration.is_none() {
                if let Some(expiration) = data.expiration {
                    async_expiration = Some(expiration.parse::<SystemTime>().unwrap());
                }
            }
            if let Some(expiration_time) = async_expiration {
                if SystemTime::now() >= expiration_time {
                    println!("Expiration reached. No response received in time.");
                    break;
                }
            }
            println!("Waiting for async response...");
            sleep(Duration::from_secs(1)).await;
        }
    }

    Ok(())
}
