import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Instant;
import java.util.UUID;
import java.util.concurrent.TimeUnit;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;

public class PixDeposit {
    private static final String URL = "https://depix.eulen.app/api/deposit";
    private static final String TOKEN = "<token>"; // Replace with your token
    private static final int MAX_ATTEMPTS = 10;

    public static void main(String[] args) {
        try {
            String nonce = UUID.randomUUID().toString();
            HttpClient client = HttpClient.newHttpClient();
            ObjectMapper mapper = new ObjectMapper();

            ObjectNode requestBody = mapper.createObjectNode();
            requestBody.put("amountInCents", 100);

            HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(URL))
                .header("X-Nonce", nonce)
                .header("Authorization", "Bearer " + TOKEN)
                .header("Content-Type", "application/json")
                .POST(HttpRequest.BodyPublishers.ofString(requestBody.toString()))
                .build();

            int attempts = 0;
            Instant asyncExpiration = null;

            while (true) {
                HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
                int statusCode = response.statusCode();

                if (statusCode != 200 && statusCode != 201 && statusCode != 202) {
                    System.out.println("Request failed with status code: " + statusCode);
                    System.out.println("Response: " + response.body());
                    break;
                }

                ObjectNode responseBody = (ObjectNode) mapper.readTree(response.body());

                if (!responseBody.get("async").asBoolean()) {
                    System.out.println("Response received: " + responseBody);
                    break;
                } else {
                    if (asyncExpiration == null) {
                        String expiration = responseBody.get("expiration").asText();
                        asyncExpiration = Instant.parse(expiration);
                    }

                    if (Instant.now().isAfter(asyncExpiration)) {
                        System.out.println("Expiration reached. No response received in time.");
                        break;
                    }

                    System.out.println("Waiting for async response...");
                    TimeUnit.SECONDS.sleep(1);
                }

                attempts++;
                if (attempts >= MAX_ATTEMPTS) {
                    System.out.println("Maximum number of attempts reached.");
                    break;
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
