import kotlinx.coroutines.delay
import kotlinx.coroutines.runBlocking
import java.net.HttpURLConnection
import java.net.URL
import java.util.UUID
import com.fasterxml.jackson.module.kotlin.jacksonObjectMapper
import com.fasterxml.jackson.module.kotlin.readValue
import java.time.Instant

const val MAX_ATTEMPTS = 10
const val API_URL = "https://depix.eulen.app/api/deposit"
const val TOKEN = "<token>" // Replace with your token

data class ApiResponse(
    val async: Boolean,
    val expiration: String?,
    val response: Map<String, String>?
)

fun generateNonce(): String {
    return UUID.randomUUID().toString().replace("-", "")
}

fun makeDeposit() = runBlocking {
    val mapper = jacksonObjectMapper()
    val nonce = generateNonce()
    val body = mapper.writeValueAsString(mapOf("amountInCents" to 100))

    var attempts = 0
    var asyncExpiration: Instant? = null

    while (true) {
        val connection = (URL(API_URL).openConnection() as HttpURLConnection).apply {
            requestMethod = "POST"
            setRequestProperty("X-Nonce", nonce)
            setRequestProperty("Authorization", "Bearer $TOKEN")
            setRequestProperty("Content-Type", "application/json")
            doOutput = true
            outputStream.use { it.write(body.toByteArray()) }
        }

        val responseCode = connection.responseCode
        val responseBody = connection.inputStream.bufferedReader().readText()
        connection.disconnect()

        if (responseCode !in 200..202) {
            println("Request failed with status code: $responseCode")
            println("Response: $responseBody")
            break
        }

        val apiResponse: ApiResponse = mapper.readValue(responseBody)

        if (!apiResponse.async) {
            println("Response received: $apiResponse")
            break
        } else {
            asyncExpiration = asyncExpiration ?: Instant.parse(apiResponse.expiration)

            if (Instant.now().isAfter(asyncExpiration)) {
                println("Expiration reached. No response received in time.")
                break
            }

            println("Waiting for async response...")
            delay(1000L)
        }

        attempts++
        if (attempts >= MAX_ATTEMPTS) {
            println("Maximum number of attempts reached.")
            break
        }
    }
}

fun main() {
    makeDeposit()
}
